import{_ as t,o as r,c as s,ak as o}from"./chunks/framework.Dga8WbZz.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),d={name:"guide/introduction.md"};function i(a,e,n,l,p,c){return r(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><p><strong>ExpressiveSharp</strong> is a Roslyn source generator that enables modern C# syntax in LINQ expression trees. It generates <code>Expression&lt;TDelegate&gt;</code> factory code at compile time, so you can use null-conditional operators, switch expressions, pattern matching, and more in queries that target EF Core or any LINQ provider.</p><h2 id="the-two-problems" tabindex="-1">The Two Problems <a class="header-anchor" href="#the-two-problems" aria-label="Permalink to “The Two Problems”">​</a></h2><p>When using C# with LINQ providers like EF Core, you hit two walls:</p><h3 id="_1-expression-tree-syntax-restrictions" tabindex="-1">1. Expression tree syntax restrictions <a class="header-anchor" href="#_1-expression-tree-syntax-restrictions" aria-label="Permalink to “1. Expression tree syntax restrictions”">​</a></h3><p>You write a perfectly reasonable query and hit:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>error CS8072: An expression tree lambda may not contain a null propagating operator</span></span></code></pre></div><p>Expression trees (<code>Expression&lt;Func&lt;...&gt;&gt;</code>) only support a restricted subset of C#. There is no <code>?.</code>, no switch expressions, no pattern matching. You end up writing ugly ternary chains instead of the clean code you would write anywhere else. For the full story of why this restriction has persisted since 2007, see <a href="./expression-tree-problem.html">The Expression Tree Problem</a>.</p><h3 id="_2-computed-properties-are-opaque-to-linq-providers" tabindex="-1">2. Computed properties are opaque to LINQ providers <a class="header-anchor" href="#_2-computed-properties-are-opaque-to-linq-providers" aria-label="Permalink to “2. Computed properties are opaque to LINQ providers”">​</a></h3><p>You define <code>public string FullName =&gt; FirstName + &quot; &quot; + LastName</code> and use it in a query, but EF Core cannot see inside the property getter. It either throws a runtime translation error, or worse, silently fetches the entire entity to evaluate <code>FullName</code> on the client (overfetching). The only workaround is to duplicate the logic as an inline expression in every query that needs it.</p><h2 id="how-expressivesharp-works" tabindex="-1">How ExpressiveSharp Works <a class="header-anchor" href="#how-expressivesharp-works" aria-label="Permalink to “How ExpressiveSharp Works”">​</a></h2><p>ExpressiveSharp fixes both problems with a two-phase design:</p><h3 id="compile-time-source-generation" tabindex="-1">Compile time (source generation) <a class="header-anchor" href="#compile-time-source-generation" aria-label="Permalink to “Compile time (source generation)”">​</a></h3><p>Two Roslyn incremental source generators analyze your code:</p><ol><li><p><strong>ExpressiveGenerator</strong> finds members decorated with <code>[Expressive]</code>, validates them, and emits <code>Expression.*</code> factory code that builds the equivalent expression tree. These are registered in a per-assembly expression registry.</p></li><li><p><strong>PolyfillInterceptorGenerator</strong> uses C# 13 method interceptors to rewrite <code>ExpressionPolyfill.Create()</code> calls and <code>IExpressiveQueryable&lt;T&gt;</code> LINQ method calls, converting delegate lambdas into expression trees at their call sites.</p></li></ol><h3 id="runtime-expression-expansion" tabindex="-1">Runtime (expression expansion) <a class="header-anchor" href="#runtime-expression-expansion" aria-label="Permalink to “Runtime (expression expansion)”">​</a></h3><p>When you query with EF Core (via <code>UseExpressives()</code>) or call <code>.ExpandExpressives()</code> manually, an <code>ExpressionVisitor</code> walks the query tree and replaces opaque <code>[Expressive]</code> member accesses with the pre-built expression trees. Transformers then adapt the trees for the target provider (stripping null-conditional patterns for SQL, flattening blocks, etc.).</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Your LINQ query</span></span>
<span class="line"><span>    -&gt; [Expressive member accesses replaced with generated expressions]</span></span>
<span class="line"><span>    -&gt; [Transformers adapt for SQL provider]</span></span>
<span class="line"><span>    -&gt; Expanded expression tree</span></span>
<span class="line"><span>    -&gt; EF Core SQL translation</span></span>
<span class="line"><span>    -&gt; SQL query</span></span></code></pre></div><p>All expression trees are generated at compile time. There is no runtime reflection or expression compilation.</p><h2 id="which-api-should-i-use" tabindex="-1">Which API Should I Use? <a class="header-anchor" href="#which-api-should-i-use" aria-label="Permalink to “Which API Should I Use?”">​</a></h2><p>Mark computed properties and methods with <code>[Expressive]</code> to generate companion expression trees. Then choose how to wire them into your queries:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>API</th></tr></thead><tbody><tr><td><strong>EF Core</strong> -- modern syntax + <code>[Expressive]</code> expansion on <code>DbSet</code></td><td><a href="./ef-core-integration.html"><code>ExpressiveDbSet&lt;T&gt;</code></a> (or <a href="./ef-core-integration.html"><code>UseExpressives()</code></a> for global expansion)</td></tr><tr><td><strong>Any <code>IQueryable</code></strong> -- modern syntax + <code>[Expressive]</code> expansion</td><td><a href="./expressive-queryable.html"><code>.AsExpressive()</code></a></td></tr><tr><td><strong>EF Core</strong> -- SQL window functions (ROW_NUMBER, RANK, etc.)</td><td><a href="./window-functions.html"><code>WindowFunction.*</code></a> (install <code>RelationalExtensions</code> package)</td></tr><tr><td><strong>Advanced</strong> -- build an <code>Expression&lt;T&gt;</code> inline, no attribute needed</td><td><a href="./expression-polyfill.html"><code>ExpressionPolyfill.Create</code></a></td></tr><tr><td><strong>Advanced</strong> -- expand <code>[Expressive]</code> members in an existing expression tree</td><td><code>.ExpandExpressives()</code></td></tr><tr><td><strong>Advanced</strong> -- make third-party/BCL members expressable</td><td><code>[ExpressiveFor]</code></td></tr></tbody></table><h2 id="comparison-with-similar-libraries" tabindex="-1">Comparison with Similar Libraries <a class="header-anchor" href="#comparison-with-similar-libraries" aria-label="Permalink to “Comparison with Similar Libraries”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>ExpressiveSharp</th><th>Projectables</th><th>Expressionify</th><th>LinqKit</th></tr></thead><tbody><tr><td>Source generator based</td><td>Yes</td><td>Yes</td><td>Yes</td><td>No</td></tr><tr><td>Works with entity methods</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Partial</td></tr><tr><td>Works with extension methods</td><td>Yes</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Composable members</td><td>Yes</td><td>Yes</td><td>No</td><td>Partial</td></tr><tr><td>Constructor projections</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td></tr><tr><td>Null-conditional <code>?.</code> rewriting</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td></tr><tr><td>Switch expressions / pattern matching</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td></tr><tr><td>Block-bodied members</td><td>Yes (experimental)</td><td>Yes (experimental)</td><td>No</td><td>No</td></tr><tr><td>Enum method expansion</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td></tr><tr><td>Inline expression creation</td><td>Yes (<code>ExpressionPolyfill.Create</code>)</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Modern syntax in LINQ chains</td><td>Yes (<code>IExpressiveQueryable&lt;T&gt;</code>)</td><td>No</td><td>No</td><td>No</td></tr><tr><td>SQL window functions</td><td>Yes (RelationalExtensions)</td><td>No</td><td>No</td><td>No</td></tr><tr><td>String interpolation support</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Tuple literals support</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>List patterns / index-range</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td><code>with</code> expressions (records)</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Collection expressions</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Customizable transformer pipeline</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Plugin architecture (EF Core)</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>External member mapping</td><td>Yes (<code>[ExpressiveFor]</code>)</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Not coupled to EF Core</td><td>Yes</td><td>No</td><td>No</td><td>No</td></tr><tr><td>Roslyn analyzers and code fixes</td><td>Yes</td><td>Yes</td><td>No</td><td>No</td></tr></tbody></table><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>.NET 8.0</th><th>.NET 10.0</th></tr></thead><tbody><tr><td><strong>ExpressiveSharp</strong></td><td>C# 12</td><td>C# 14</td></tr><tr><td><strong>ExpressiveSharp.Abstractions</strong></td><td>C# 12</td><td>C# 14</td></tr><tr><td><strong>ExpressiveSharp.EntityFrameworkCore</strong></td><td>EF Core 8.x</td><td>EF Core 10.x</td></tr><tr><td><strong>ExpressiveSharp.EntityFrameworkCore.RelationalExtensions</strong></td><td>EF Core 8.x</td><td>EF Core 10.x</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><a href="./quickstart.html">Quick Start</a> -- install, configure, and run your first query</li><li><a href="./expressive-properties.html">[Expressive] Properties</a> -- computed properties translated to SQL</li><li><a href="./ef-core-integration.html">EF Core Integration</a> -- full setup for Entity Framework Core</li></ul>`,28)])])}const m=t(d,[["render",i]]);export{u as __pageData,m as default};
